"use client";

import React from "react";

export default function ThemeToggle() {
  return (
    <button
      onClick={() => {
        if (typeof window !== "undefined" && (window as any).toggleTheme) {
          (window as any).toggleTheme();
        }
      }}
      className="fixed bottom-6 left-6 z-[1000] px-1 py-1 border border-white bg-[#0a0a0a] text-white font-bold text-[14px] cursor-pointer relative overflow-hidden transition-colors duration-300 hover:text-orange-500"
      style={{
        fontFamily: "'Plus Jakarta Sans', sans-serif",
        lineHeight: "1",
      }}
    >
      <span className="relative z-10">Light/Darkdd</span>

      <span className="absolute left-1/2 top-1/2 h-0 w-[150%] -translate-x-1/2 -translate-y-1/2 -rotate-[25deg] bg-white transition-all duration-700 ease-out hover:h-[450%]"></span>
    </button>
  );
}